    (function () {
      try {
        var select = document.getElementById('colorPicker');
        var heading = document.getElementById('greeting');
        if (!select || !heading) return;

        var colorClasses = [
          'text-gray-900',
          'text-red-600',
          'text-blue-600',
          'text-green-600',
          'text-purple-600',
          'text-orange-600',
          'text-black'
        ];

        function updateColor(cls) {
          try {
            colorClasses.forEach(function (c) { heading.classList.remove(c); });
            if (cls && colorClasses.indexOf(cls) !== -1) {
              heading.classList.add(cls);
            }
          } catch (e) {
            // noop: keep UI resilient
          }
        }

        select.addEventListener('change', function (e) {
          var value = (e.target && e.target.value) || 'text-gray-900';
          updateColor(value);
        });

        // initialize with current select value
